SELECT h.user_id AS userId, COALESCE(MAX(u.user_tg_id), MAX(h.user_tg_id)) AS userTgId, COALESCE(MAX(u.user_tg_name), MAX(h.user_tg_name)) AS userTgName, COALESCE(MAX(u.user_tg_username), MAX(h.user_tg_username)) AS userTgUsername, GROUP_CONCAT(DISTINCT h.ip ORDER BY h.create_time DESC SEPARATOR ',') AS currentIp, GROUP_CONCAT(DISTINCT h.ip_addr ORDER BY h.create_time DESC SEPARATOR ',') AS currentIpAddr, COUNT(1) AS loginCount, MAX(h.create_time) AS lastLoginTime FROM t_user_login_history h LEFT JOIN t_user u ON u.user_id = h.user_id WHERE h.type = 1 AND h.ip IS NOT NULL AND h.ip != '' AND h.ip IN
#{ip}
AND h.user_id != #{excludeUserId} GROUP BY h.user_id ORDER BY loginCount DESC, lastLoginTime DESC

mapper.update:
update t_user_login_history
user_id = #{userId}, user_tg_id = #{userTgId}, user_tg_name = #{userTgName}, user_tg_username = #{userTgUsername}, ip = #{ip}, ip_addr = #{ipAddr}, type = #{type}, device = #{device}, fingerprint = #{fingerprint}, create_time = #{createTime},
where id = #{id}
